class Solution(object):
    def tree2str(self, root):
        def dfs(node):
            if not node:
                return ''
            s = str(node.val)
            if not node.left and not node.right:
                return s
            left = dfs(node.left)
            right = dfs(node.right)
            if not right:
                s += '(' + left + ')'
            else:
                s += '(' + left + ')(' + right + ')'
            return s
        return dfs(root)
